import React, { useState, useEffect } from 'react';
import { fetchEventData, fetchEventsByName } from '../services/ftcScoutApi';
import '../styles/EventSearch.css';

interface EventOption {
    id: string;
    name: string;
    year: string;
    location: string;
}

const EventSearch: React.FC = () => {
    const [eventName, setEventName] = useState('');
    const [year, setYear] = useState('2025-2026');
    const [eventData, setEventData] = useState(null);
    const [error, setError] = useState('');
    const [suggestions, setSuggestions] = useState<EventOption[]>([]);
    const [showDropdown, setShowDropdown] = useState(false);
    const [loading, setLoading] = useState(false);

    // Mock event data - in production, fetch from API
    const mockEvents: EventOption[] = [
        { id: '1', name: 'Houston Robotics Championship', year: '2025-2026', location: 'Houston, TX' },
        { id: '2', name: 'San Diego Super Regional', year: '2025-2026', location: 'San Diego, CA' },
        { id: '3', name: 'Dallas Invitational', year: '2025-2026', location: 'Dallas, TX' },
        { id: '4', name: 'Austin State Championship', year: '2025-2026', location: 'Austin, TX' },
        { id: '5', name: 'Houston Robotics Championship', year: '2024-2025', location: 'Houston, TX' },
        { id: '6', name: 'San Diego Super Regional', year: '2024-2025', location: 'San Diego, CA' },
    ];

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const value = e.target.value;
        setEventName(value);

        if (value.trim().length > 0) {
            // Filter mock events by name and year
            const filtered = mockEvents.filter(
                event => event.name.toLowerCase().includes(value.toLowerCase()) && event.year === year
            );
            setSuggestions(filtered);
            setShowDropdown(true);
        } else {
            setSuggestions([]);
            setShowDropdown(false);
        }
    };

    const handleSelectEvent = (event: EventOption) => {
        setEventName(event.name);
        setSuggestions([]);
        setShowDropdown(false);
        handleSearch(event);
    };

    const handleSearch = async (selectedEvent?: EventOption) => {
        const eventToSearch = selectedEvent || { 
            id: '1', 
            name: eventName, 
            year, 
            location: 'Location TBD' 
        };

        if (!eventToSearch.name.trim()) {
            setError('Please enter or select an event name.');
            return;
        }

        setError('');
        setLoading(true);

        try {
            // Simulate API call
            const data = await fetchEventData(eventToSearch.name);
            // @ts-ignore
            setEventData({
                ...data,
                year,
                eventId: eventToSearch.id,
                location: eventToSearch.location,
            });
        } catch (err) {
            setError('Error fetching event data. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    const years = ['2025-2026', '2024-2025', '2023-2024'];

    return (
        <div className="event-search-container neon-card">
            <h2>Event Finder</h2>

            <div className="search-controls">
                <div className="year-selector">
                    <label htmlFor="year">Season:</label>
                    <select 
                        id="year"
                        value={year} 
                        onChange={(e) => {
                            setYear(e.target.value);
                            setEventName('');
                            setSuggestions([]);
                        }}
                    >
                        {years.map(y => (
                            <option key={y} value={y}>{y}</option>
                        ))}
                    </select>
                </div>

                <div className="search-input-wrapper">
                    <input
                        type="text"
                        value={eventName}
                        onChange={handleInputChange}
                        onFocus={() => eventName && setSuggestions(
                            mockEvents.filter(e => 
                                e.name.toLowerCase().includes(eventName.toLowerCase()) && e.year === year
                            )
                        )}
                        placeholder="Search for an event..."
                    />
                    {showDropdown && suggestions.length > 0 && (
                        <div className="autocomplete-dropdown">
                            {suggestions.map((event) => (
                                <div
                                    key={event.id}
                                    className="autocomplete-item"
                                    onClick={() => handleSelectEvent(event)}
                                >
                                    <div className="event-name">{event.name}</div>
                                    <div className="event-location">{event.location}</div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                <button 
                    className="neon-button neon-button-pink"
                    onClick={() => handleSearch()}
                    disabled={loading}
                >
                    {loading ? 'Searching...' : 'Search'}
                </button>
            </div>

            {error && <p className="error-message">{error}</p>}

            {eventData && (
                <div className="event-info">
                    <h3>{eventData.name}</h3>
                    <p><strong>Location:</strong> {eventData.location}</p>
                    <p><strong>Season:</strong> {eventData.year}</p>
                    <p><strong>Matches:</strong> {eventData.matches?.length || 0}</p>
                </div>
            )}
        </div>
    );
};

export default EventSearch;
